org.machanism.machai.ai.provider.Genai genai = org.machanism.machai.ai.manager.GenaiProviderManager.getProvider("OpenAI:gpt-4.1", new org.machanism.macha.core.commons.configurator.Configurator());
genai.setWorkingDir(new java.io.File("."));
genai.addTool("echo", "Echo back a message", (java.lang.Object[] args) -> {
  com.fasterxml.jackson.databind.JsonNode json = (com.fasterxml.jackson.databind.JsonNode) args[0];
  java.lang.String msg = json.has("message") ? json.get("message").asText() : "";
  return "Echo: " + msg;
}, "message:string:required:The message to echo");
genai.prompt("Call the echo tool with message=Hello");
java.lang.String response = genai.perform();

